   1→/**
   2→ * Batch execution and dependency handling for sequant run.
   3→ *
   4→ * Contains functions for fetching issue metadata, parsing and sorting
   5→ * dependencies, splitting issues into batches, reading environment-based
   6→ * configuration, and orchestrating the execution of individual issues
   7→ * (including quality-loop retries, checkpoint commits, rebasing, and PR
   8→ * creation).
   9→ */
  10→
  11→import chalk from "chalk";
  12→import { spawnSync } from "child_process";
  13→import { LogWriter, createPhaseLogFromTiming } from "./log-writer.js";
  14→import { StateManager } from "./state-manager.js";
  15→import { Phase, ExecutionConfig, PhaseResult, IssueResult } from "./types.js";
  16→import { classifyError } from "./error-classifier.js";
  17→import type { ErrorContext } from "./run-log-schema.js";
  18→import { ShutdownManager } from "../shutdown.js";
  19→import { PhaseSpinner } from "../phase-spinner.js";
  20→import { getGitDiffStats, getCommitHash } from "./git-diff-utils.js";
  21→import type { WorktreeInfo } from "./worktree-manager.js";
  22→import {
  23→  createCheckpointCommit,
  24→  rebaseBeforePR,
  25→  createPR,
  26→  readCacheMetrics,
  27→  filterResumedPhases,
  28→} from "./worktree-manager.js";
  29→import { executePhaseWithRetry } from "./phase-executor.js";
  30→import {
  31→  detectPhasesFromLabels,
  32→  parseRecommendedWorkflow,
  33→  determinePhasesForIssue,
  34→  BUG_LABELS,
  35→  DOCS_LABELS,
  36→} from "./phase-mapper.js";
  37→
  38→/**
  39→ * Emit a structured progress line to stderr for MCP progress notifications.
  40→ * Only emits when running under an orchestrator (e.g., MCP server).
  41→ * The MCP handler parses these lines to send `notifications/progress`.
  42→ *
  43→ * @param issue - GitHub issue number
  44→ * @param phase - Phase name (e.g., "spec", "exec", "qa")
  45→ * @param event - Phase lifecycle event: "start", "complete", or "failed"
  46→ * @param extra - Optional fields: durationSeconds (on complete), error (on failed)
  47→ */
  48→export function emitProgressLine(
  49→  issue: number,
  50→  phase: string,
  51→  event: "start" | "complete" | "failed" = "start",
  52→  extra?: { durationSeconds?: number; error?: string },
  53→): void {
  54→  if (!process.env.SEQUANT_ORCHESTRATOR) return;
  55→  const payload: Record<string, unknown> = { issue, phase, event };
  56→  if (extra?.durationSeconds !== undefined) {
  57→    payload.durationSeconds = extra.durationSeconds;
  58→  }
  59→  if (extra?.error !== undefined) {
  60→    payload.error = extra.error;
  61→  }
  62→  const line = `SEQUANT_PROGRESS:${JSON.stringify(payload)}\n`;
  63→  process.stderr.write(line);
  64→}
  65→
  66→export interface RunOptions {
  67→  phases?: string;
  68→  sequential?: boolean;
  69→  dryRun?: boolean;
  70→  verbose?: boolean;
  71→  timeout?: number;
  72→  logJson?: boolean;
  73→  noLog?: boolean;
  74→  logPath?: string;
  75→  qualityLoop?: boolean;
  76→  maxIterations?: number;
  77→  batch?: string[];
  78→  smartTests?: boolean;
  79→  noSmartTests?: boolean;
  80→  testgen?: boolean;
  81→  autoDetectPhases?: boolean;
  82→  /** Enable automatic worktree creation for issue isolation */
  83→  worktreeIsolation?: boolean;
  84→  /** Reuse existing worktrees instead of creating new ones */
  85→  reuseWorktrees?: boolean;
  86→  /** Suppress version warnings and non-essential output */
  87→  quiet?: boolean;
  88→  /** Chain issues: each branches from previous (requires --sequential) */
  89→  chain?: boolean;
  90→  /**
  91→   * Wait for QA pass before starting next issue in chain mode.
  92→   * When enabled, the chain pauses if QA fails, preventing downstream issues
  93→   * from building on potentially broken code.
  94→   */
  95→  qaGate?: boolean;
  96→  /**
  97→   * Base branch for worktree creation.
  98→   * Resolution priority: this CLI flag → settings.run.defaultBase → 'main'
  99→   */
 100→  base?: string;
 101→  /**
 102→   * Disable MCP servers in headless mode.
 103→   * When true, MCPs are not passed to the SDK (faster/cheaper runs).
 104→   * Resolution priority: this CLI flag → settings.run.mcp → default (true)
 105→   */
 106→  noMcp?: boolean;
 107→  /**
 108→   * Resume from last completed phase.
 109→   * Reads phase markers from GitHub issue comments and skips completed phases.
 110→   */
 111→  resume?: boolean;
 112→  /**
 113→   * Disable automatic retry with MCP fallback.
 114→   * When true, no retry attempts are made on phase failure.
 115→   * Useful for debugging to see the actual failure without retry masking it.
 116→   */
 117→  noRetry?: boolean;
 118→  /**
 119→   * Skip pre-PR rebase onto the base branch.
 120→   * When true, branches are not rebased before creating the PR.
 121→   * Use when you want to preserve branch state or handle rebasing manually.
 122→   */
 123→  noRebase?: boolean;
 124→  /**
 125→   * Skip PR creation after successful QA.
 126→   * When true, branches are pushed but no PR is created.
 127→   * Useful for manual workflows where PRs are created separately.
 128→   */
 129→  noPr?: boolean;
 130→  /**
 131→   * Force re-execution of issues even if they have completed status.
 132→   * Bypasses the pre-flight state guard that skips ready_for_merge/merged issues.
 133→   */
 134→  force?: boolean;
 135→  /**
 136→   * Analyze run results and suggest workflow improvements.
 137→   * Displays observations about timing patterns, phase mismatches, and
 138→   * actionable suggestions after the summary output.
 139→   */
 140→  reflect?: boolean;
 141→  /**
 142→   * Max concurrent issues in parallel mode (default: 3).
 143→   * Only applies when --sequential is not set.
 144→   */
 145→  concurrency?: number;
 146→  /**
 147→   * Agent driver for phase execution.
 148→   * Default: "claude-code"
 149→   */
 150→  agent?: string;
 151→}
