  1→/**
  2→ * Reconciliation engine for sequant status
  3→ *
  4→ * Reconciles local state.json with GitHub API and filesystem
  5→ * to provide accurate, up-to-date status information.
  6→ *
  7→ * @module reconcile
  8→ */
  9→
 10→import * as fs from "fs";
 11→import { StateManager } from "./state-manager.js";
 12→import {
 13→  GitHubProvider,
 14→  type BatchIssueInfo,
 15→  type BatchPRInfo,
 16→} from "./platforms/github.js";
 17→import type { IssueState, IssueStatus } from "./state-schema.js";
 18→
 19→/**
 20→ * Classification of detected drift between local state and reality.
 21→ */
 22→export type DriftType = "unambiguous" | "ambiguous" | "none";
 23→
 24→/**
 25→ * A single drift action detected during reconciliation.
 26→ */
 27→export interface DriftAction {
 28→  issueNumber: number;
 29→  type: DriftType;
 30→  action: string;
 31→  description: string;
 32→}
 33→
 34→/**
 35→ * Result of a reconciliation operation.
 36→ */
 37→export interface ReconcileResult {
 38→  success: boolean;
 39→  /** Actions taken (unambiguous drift auto-healed). */
 40→  healed: DriftAction[];
 41→  /** Ambiguous drift flagged to user. */
 42→  warnings: DriftAction[];
 43→  /** ISO timestamp of when reconciliation completed. */
 44→  lastSynced: string;
 45→  /** Whether GitHub was reachable. */
 46→  githubReachable: boolean;
 47→  /** Error message if reconciliation failed entirely. */
 48→  error?: string;
 49→}
 50→
 51→/**
 52→ * Options for reconciliation.
 53→ */
 54→export interface ReconcileOptions {
 55→  /** Skip GitHub API queries (offline mode). */
 56→  offline?: boolean;
 57→  /** State manager to use. */
 58→  stateManager?: StateManager;
 59→}
 60→
 61→/**
 62→ * Classify drift for a single issue based on GitHub and filesystem state.
 63→ */
 64→export function classifyDrift(
 65→  issue: IssueState,
 66→  githubIssue?: BatchIssueInfo,
 67→  githubPR?: BatchPRInfo,
 68→  worktreeExists?: boolean,
 69→): DriftAction | null {
 70→  const num = issue.number;
 71→
 72→  // Check PR merge → unambiguous
 73→  if (githubPR?.state === "MERGED" && issue.status !== "merged") {
 74→    return {
 75→      issueNumber: num,
 76→      type: "unambiguous",
 77→      action: "update_to_merged",
 78→      description: `PR #${githubPR.number} merged on GitHub`,
 79→    };
 80→  }
 81→
 82→  // Check issue closed + no merged PR → unambiguous abandoned
 83→  if (
 84→    githubIssue?.state === "CLOSED" &&
 85→    issue.status !== "merged" &&
 86→    issue.status !== "abandoned" &&
 87→    githubPR?.state !== "MERGED"
 88→  ) {
 89→    return {
 90→      issueNumber: num,
 91→      type: "unambiguous",
 92→      action: "update_to_abandoned",
 93→      description: `Issue #${num} closed on GitHub without merged PR`,
 94→    };
 95→  }
 96→
 97→  // Check worktree missing
 98→  if (issue.worktree && worktreeExists === false) {
 99→    if (!issue.pr?.number) {
100→      if (githubIssue?.state === "OPEN") {
101→        // Confirmed open on GitHub, no PR → ambiguous
102→        return {
103→          issueNumber: num,
104→          type: "ambiguous",
105→          action: "flag_missing_worktree",
106→          description: `Worktree deleted but issue #${num} still open on GitHub with no PR`,
107→        };
108→      }
109→      if (!githubIssue) {
110→        // GitHub data unavailable → ambiguous (can't determine if safe to clear)
111→        return {
112→          issueNumber: num,
113→          type: "ambiguous",
114→          action: "flag_missing_worktree",
115→          description: `Worktree deleted for issue #${num} but GitHub state unknown (API unreachable)`,
116→        };
117→      }
118→    }
119→    // Otherwise just clear worktree (unambiguous)
120→    return {
121→      issueNumber: num,
122→      type: "unambiguous",
123→      action: "clear_worktree",
124→      description: `Worktree path no longer exists for issue #${num}`,
125→    };
126→  }
127→
128→  // Check local abandoned but GitHub open → ambiguous
129→  if (issue.status === "abandoned" && githubIssue?.state === "OPEN") {
130→    return {
131→      issueNumber: num,
132→      type: "ambiguous",
133→      action: "flag_status_mismatch",
134→      description: `Issue #${num} marked abandoned locally but still open on GitHub`,
135→    };
136→  }
137→
138→  return null;
139→}
140→
141→/**
142→ * Get a next-action hint for an issue based on its current state.
143→ */
144→export function getNextActionHint(issue: IssueState): string {
145→  switch (issue.status) {
146→    case "not_started":
147→      return `sequant run ${issue.number}`;
148→    case "in_progress": {
149→      // Suggest resuming at current phase or next phase
150→      if (issue.currentPhase) {
151→        const failedPhase = Object.entries(issue.phases).find(
152→          ([, ps]) => ps.status === "failed",
153→        );
154→        if (failedPhase) {
155→          return `sequant run ${issue.number} --phase ${failedPhase[0]}`;
156→        }
157→      }
158→      return `sequant run ${issue.number}`;
159→    }
160→    case "waiting_for_qa_gate":
161→      return `sequant run ${issue.number} --phase qa`;
162→    case "ready_for_merge":
163→      if (issue.pr?.number) {
164→        return `gh pr merge ${issue.pr.number}`;
165→      }
166→      return `gh pr merge`;
167→    case "blocked":
168→      return `resolve blockers, then sequant run ${issue.number}`;
169→    case "merged":
170→      return `sequant status --cleanup`;
171→    case "abandoned":
172→      return `reopen issue or sequant status --cleanup`;
173→    default:
174→      return "";
175→  }
176→}
177→
178→/**
179→ * Format a relative time string from an ISO timestamp.
180→ */
181→export function formatRelativeTime(isoTimestamp: string | undefined): string {
182→  if (!isoTimestamp) return "unknown";
183→
184→  const date = new Date(isoTimestamp);
185→  if (isNaN(date.getTime())) return "unknown";
186→
187→  const now = new Date();
188→  const diffMs = now.getTime() - date.getTime();
189→
190→  // Handle future timestamps (clock skew)
191→  if (diffMs < 0) return "just now";
192→
193→  const diffSec = Math.floor(diffMs / 1000);
194→  const diffMin = Math.floor(diffSec / 60);
195→  const diffHour = Math.floor(diffMin / 60);
196→  const diffDay = Math.floor(diffHour / 24);
197→
198→  if (diffSec < 60) return "just now";
199→  if (diffMin < 60) return `${diffMin} minute${diffMin > 1 ? "s" : ""} ago`;
200→  if (diffHour < 24) return `${diffHour} hour${diffHour > 1 ? "s" : ""} ago`;
201→  if (diffDay < 7) return `${diffDay} day${diffDay > 1 ? "s" : ""} ago`;
202→  return date.toLocaleDateString();
203→}
204→
205→/**
206→ * Reconcile local workflow state with GitHub and filesystem.
207→ *
208→ * This is the main entry point for reconciliation. Called by:
209→ * - `sequant status` (CLI)
210→ * - `sequant_status` (MCP tool)
211→ */
212→export async function reconcileState(
213→  options: ReconcileOptions = {},
214→): Promise<ReconcileResult> {
215→  const stateManager = options.stateManager ?? new StateManager();
216→  const now = new Date().toISOString();
217→
218→  if (!stateManager.stateExists()) {
219→    return {
220→      success: true,
221→      healed: [],
222→      warnings: [],
223→      lastSynced: now,
224→      githubReachable: !options.offline,
225→    };
226→  }
227→
228→  try {
229→    const state = await stateManager.getState();
230→    const issues = Object.values(state.issues);
231→
232→    if (issues.length === 0) {
233→      state.lastSynced = now;
234→      await stateManager.saveState(state);
235→      return {
236→        success: true,
237→        healed: [],
238→        warnings: [],
239→        lastSynced: now,
240→        githubReachable: !options.offline,
241→      };
242→    }
243→
244→    // Collect issue and PR numbers to query
245→    const issueNumbers = issues.map((i) => i.number);
246→    const prNumbers = issues
247→      .filter((i) => i.pr?.number)
248→      .map((i) => i.pr!.number);
249→
250→    // Batch fetch from GitHub (unless offline)
251→    let githubIssues: Record<number, BatchIssueInfo> = {};
252→    let githubPRs: Record<number, BatchPRInfo> = {};
253→    let githubReachable = false;
254→
255→    if (!options.offline) {
256→      const github = new GitHubProvider();
257→      const batchResult = github.batchFetchIssueAndPRStatus(
258→        issueNumbers,
259→        prNumbers,
260→      );
261→
262→      if (!batchResult.error) {
263→        githubIssues = batchResult.issues;
264→        githubPRs = batchResult.pullRequests;
265→        githubReachable = true;
266→      }
267→      // On error: graceful degradation — proceed with cached data
268→    }
269→
270→    // Check filesystem for worktrees
271→    const worktreeExists: Record<number, boolean> = {};
272→    for (const issue of issues) {
273→      if (issue.worktree) {
274→        worktreeExists[issue.number] = fs.existsSync(issue.worktree);
275→      }
276→    }
277→
278→    // Classify and apply drift
279→    const healed: DriftAction[] = [];
280→    const warnings: DriftAction[] = [];
281→    let stateModified = false;
282→
283→    for (const issue of issues) {
284→      const issueKey = String(issue.number);
285→      const ghIssue = githubIssues[issue.number];
286→      const ghPR = issue.pr?.number ? githubPRs[issue.pr.number] : undefined;
287→      const wtExists = issue.worktree
288→        ? worktreeExists[issue.number]
289→        : undefined;
290→
291→      // Update title from GitHub if available
292→      if (ghIssue?.title && ghIssue.title !== issue.title) {
293→        state.issues[issueKey].title = ghIssue.title;
294→        stateModified = true;
295→      }
296→
297→      const drift = classifyDrift(issue, ghIssue, ghPR, wtExists);
298→
299→      // Always clear missing worktrees independently of other drift
300→      if (issue.worktree && wtExists === false && drift?.type !== "ambiguous") {
301→        state.issues[issueKey].worktree = undefined;
302→        stateModified = true;
303→      }
304→
305→      if (!drift) continue;
306→
307→      if (drift.type === "unambiguous") {
308→        // Auto-heal
309→        switch (drift.action) {
310→          case "update_to_merged":
311→            state.issues[issueKey].status = "merged" as IssueStatus;
312→            state.issues[issueKey].lastActivity = now;
313→            stateModified = true;
314→            break;
315→          case "update_to_abandoned":
316→            state.issues[issueKey].status = "abandoned" as IssueStatus;
317→            state.issues[issueKey].lastActivity = now;
318→            stateModified = true;
319→            break;
320→          case "clear_worktree":
321→            state.issues[issueKey].worktree = undefined;
322→            state.issues[issueKey].lastActivity = now;
323→            stateModified = true;
324→            break;
325→        }
326→        healed.push(drift);
327→      } else {
328→        // Flag to user
329→        warnings.push(drift);
330→      }
331→    }
332→
333→    // Persist if changed
334→    if (stateModified || githubReachable) {
335→      state.lastSynced = now;
336→      await stateManager.saveState(state);
337→    }
338→
339→    return {
340→      success: true,
341→      healed,
342→      warnings,
343→      lastSynced: now,
344→      githubReachable,
345→    };
346→  } catch (error) {
347→    return {
348→      success: false,
349→      healed: [],
350→      warnings: [],
351→      lastSynced: now,
352→      githubReachable: false,
353→      error: error instanceof Error ? error.message : String(error),
354→    };
355→  }
356→}
