301→    options?: {
302→      error?: string;
303→      iteration?: number;
304→    },
305→  ): Promise<void> {
306→    await this.withLock(async () => {
307→      const state = await this.getState();
308→      const issueState = state.issues[String(issueNumber)];
309→
310→      if (!issueState) {
