import type { ProgressCallback } from './src/lib/workflow/batch-executor.ts';

// Simulate the onPhaseProgress callback from run.ts parallel mode
const formatElapsedTime = (sec: number) => sec >= 60 ? Math.floor(sec/60) + 'm ' + (sec%60) + 's' : sec + 's';
const colors = { success: (s: string) => '\x1b[32m' + s + '\x1b[0m', error: (s: string) => '\x1b[31m' + s + '\x1b[0m', warning: (s: string) => '\x1b[33m' + s + '\x1b[0m' };

const onPhaseProgress: ProgressCallback = (issue, phase, event, extra) => {
  let line: string;
  if (event === 'start') {
    line = '  ' + colors.warning('●') + ' #' + issue + ': ' + phase + ' started';
  } else if (event === 'complete') {
    const dur = extra?.durationSeconds != null ? ' (' + formatElapsedTime(extra.durationSeconds) + ')' : '';
    line = '  ' + colors.success('●') + ' #' + issue + ': ' + phase + ' ✓' + dur;
  } else {
    line = '  ' + colors.error('●') + ' #' + issue + ': ' + phase + ' ✗';
  }
  console.log(line);
};

