const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'sequant-ac8-'));
const statePath = path.join(tmpDir, 'state.json');

const sm = new StateManager({ statePath });

(async () => {
  // Initialize issue with spec phase
  await sm.initializeIssue(100, 'Test issue');
  await sm.updatePhaseStatus(100, 'spec', 'completed');

  // Now simulate: running process updates to exec while reconcile runs concurrently
  const [reconcileResult] = await Promise.all([
    reconcileState({ stateManager: sm, offline: true }),
    new Promise<void>(resolve => setTimeout(async () => {
      await sm.updatePhaseStatus(100, 'exec', 'in_progress');
      resolve();
    }, 5)),
  ]);

  // Check final state — the running process's update should be reflected
  sm.clearCache();
  const state = await sm.getState();
  const issue = state.issues['100'];

